package com.example.app.deeplink

import android.content.Context
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import com.example.app.ui.ProfileActivity
import com.example.app.ui.PaymentActivity
import com.example.app.ui.MainActivity
import com.example.app.auth.AuthManager
import com.example.app.analytics.AnalyticsLogger

class DeepLinkHandlerActivity : AppCompatActivity() {

    private lateinit var authManager: AuthManager
    private lateinit var analyticsLogger: AnalyticsLogger

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        authManager = AuthManager.getInstance(this)
        analyticsLogger = AnalyticsLogger.getInstance()

        val uri = intent?.data
        if (uri != null) {
            handleDeepLink(uri)
        } else {
            navigateToDefault()
        }
        finish()
    }

    private fun handleDeepLink(uri: Uri) {
        analyticsLogger.logDeepLinkReceived(uri.toString())

        if (!isValidScheme(uri)) {
            analyticsLogger.logDeepLinkError("Invalid scheme", uri.toString())
            navigateToDefault()
            return
        }

        if (!isValidHost(uri)) {
            analyticsLogger.logDeepLinkError("Invalid host", uri.toString())
            navigateToDefault()
            return
        }

        val pathSegments = uri.pathSegments
        if (pathSegments.isEmpty()) {
            navigateToDefault()
            return
        }

        val route = pathSegments[0]
        when (route) {
            "profile" -> handleProfileRoute(pathSegments)
            "payment" -> handlePaymentRoute(pathSegments)
            else -> {
                analyticsLogger.logDeepLinkError("Unknown route", uri.toString())
                navigateToDefault()
            }
        }
    }

    private fun isValidScheme(uri: Uri): Boolean {
        return uri.scheme == "myapp"
    }

    private fun isValidHost(uri: Uri): Boolean {
        val allowedHosts = setOf("", null)
        return allowedHosts.contains(uri.host)
    }

    private fun handleProfileRoute(pathSegments: List<String>) {
        if (pathSegments.size < 2) {
            analyticsLogger.logDeepLinkError("Missing profile ID", "profile")
            navigateToDefault()
            return
        }

        val profileId = pathSegments[1]
        if (!isValidProfileId(profileId)) {
            analyticsLogger.logDeepLinkError("Invalid profile ID", profileId)
            navigateToDefault()
            return
        }

        if (!authManager.isUserAuthenticated()) {
            analyticsLogger.logDeepLinkError("User not authenticated", "profile")
            navigateToLogin(DeepLinkData("profile", profileId))
            return
        }

        val normalizedProfileId = normalizeProfileId(profileId)
        navigateToProfile(normalizedProfileId)
    }

    private fun handlePaymentRoute(pathSegments: List<String>) {
        if (pathSegments.size < 2) {
            analyticsLogger.logDeepLinkError("Missing payment action", "payment")
            navigateToDefault()
            return
        }

        val action = pathSegments[1]
        if (!isValidPaymentAction(action)) {
            analyticsLogger.logDeepLinkError("Invalid payment action", action)
            navigateToDefault()
            return
        }

        if (!authManager.isUserAuthenticated()) {
            analyticsLogger.logDeepLinkError("User not authenticated", "payment")
            navigateToLogin(DeepLinkData("payment", action))
            return
        }

        if (!authManager.hasPaymentPermission()) {
            analyticsLogger.logDeepLinkError("User lacks payment permission", "payment")
            navigateToDefault()
            return
        }

        when (action) {
            "confirm" -> navigateToPaymentConfirm()
            else -> navigateToDefault()
        }
    }

    private fun isValidProfileId(profileId: String): Boolean {
        return profileId.matches(Regex("^[0-9]{1,10}$"))
    }

    private fun normalizeProfileId(profileId: String): String {
        return profileId.toLongOrNull()?.toString() ?: "0"
    }

    private fun isValidPaymentAction(action: String): Boolean {
        val allowedActions = setOf("confirm")
        return allowedActions.contains(action)
    }

    private fun navigateToProfile(profileId: String) {
        val intent = Intent(this, ProfileActivity::class.java).apply {
            putExtra(ProfileActivity.EXTRA_PROFILE_ID, profileId)
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        }
        analyticsLogger.logDeepLinkSuccess("profile", profileId)
        startActivity(intent)
    }

    private fun navigateToPaymentConfirm() {
        val intent = Intent(this, PaymentActivity::class.java).apply {
            putExtra(PaymentActivity.EXTRA_ACTION, "confirm")
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        }
        analyticsLogger.logDeepLinkSuccess("payment", "confirm")
        startActivity(intent)
    }

    private fun navigateToLogin(pendingDeepLink: DeepLinkData? = null) {
        val intent = Intent(this, MainActivity::class.java).apply {
            putExtra("show_login", true)
            pendingDeepLink?.let {
                putExtra("pending_deeplink_route", it.route)
                putExtra("pending_deeplink_param", it.param)
            }
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        }
        startActivity(intent)
    }

    private fun navigateToDefault() {
        val intent = Intent(this, MainActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        }
        startActivity(intent)
    }

    private data class DeepLinkData(val route: String, val param: String)
}

class AuthManager private constructor(context: Context) {
    
    private val sharedPreferences = context.getSharedPreferences("auth_prefs", Context.MODE_PRIVATE)

    fun isUserAuthenticated(): Boolean {
        return sharedPreferences.getBoolean("is_authenticated", false)
    }

    fun hasPaymentPermission(): Boolean {
        return sharedPreferences.getBoolean("has_payment_permission", false)
    }

    companion object {
        @Volatile
        private var instance: AuthManager? = null

        fun getInstance(context: Context): AuthManager {
            return instance ?: synchronized(this) {
                instance ?: AuthManager(context.applicationContext).also { instance = it }
            }
        }
    }
}

